INSERT INTO `products` (`id`, `name`, `slug`, `sku`, `category`, `brand`, `price`, `sellable_price`, `stock`, `weight`, `has_variants`, `is_featured`, `status`, `attribute_definitions`, `image`, `description`, `short_description`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES
(9, 'Micro Ingredients Vitamin D3 10,000 IU + K2 MK-7 200 mcg, 300 Softgels with Virgin Coconut Oil | 2-in-1 Vitamins D & K Complex | Extra Strength, Easy to Swallow, Non-GMO, Gluten Free', 'micro-ingredients-vitamin-d3-10000-iu-k2-mk-7-200-mcg-300-softgels-with-virgin-coconut-oil-2-in-1-vitamins-d-k-complex-extra-strength-easy-to-swallow-non-gmo-gluten-free', 'MC-123', 'Medicine and Supplements', 'Amazon USA', 6571.00, 5600.00, 20, 0.00, 0, 1, 'published', NULL, 'products/images/kXbbmeevjQWd8C0UW2lGM16rjNjvBEi7sBeyvMxZ.jpg', '<ul><li>Micro Ingredients offers double-strength vitamin D3 + K2 softgels. An efficiently absorbed 2-in-1 formula featuring D3 as cholecalciferol and K2 in its top-grade menaquinone-7 (MK-7) form.</li><li>Each pouch includes 300 mini softgels infused with coconut oil, delivering a potent one a day complex with 10,000 IU of vitamin D3 and 200 mcg of vitamin K2 per serving to provide natural sunshine vitamin synergy.</li><li>Fat soluble vitamins like D and K are absorbed more effectively when a fat source is present. The addition of MCT coconut oil provides a clean, natural carrier for optimal nutrient delivery.</li><li>Vitamin D3 and K2 are essential micronutrients for adults, offered in high quality, stable forms that pair together for closely related and comprehensive benefits.</li><li>Premium non-GMO vitamin D3 + K2 supplements. Made without soy, dairy, and gluten. Ingredients must pass a 3rd party lab test to ensure our product is safe, pure, and potent.</li></ul><p><br></p>', 'Micro Ingredients Vitamin D3 10,000 IU + K2 MK-7 200 mcg, 300 Softgels with Virgin Coconut Oil | 2-in-1 Vitamins D & K Complex | Extra Strength, Easy to Swallow, Non-GMO, Gluten Free', 'Micro Ingredients Vitamin D3 10,000 IU + K2 MK-7 200 mcg, 300 Softgels with Virgin Coconut Oil | 2-in-1 Vitamins D & K Complex | Extra Strength, Easy to Swallow, Non-GMO, Gluten Free | Amazon USA', 'Shop Micro Ingredients Vitamin D3 10,000 IU + K2 MK-7 200 mcg, 300 Softgels with Virgin Coconut Oil | 2-in-1 Vitamins D & K Complex | Extra Strength, Easy to Swallow, Non-GMO, Gluten Free. High quality product with great features.', '2026-03-30 23:53:24', '2026-04-18 16:00:45'),
(10, 'Men’s Rogaine 5% Minoxidil for Men Foam, Clinically Proven Regrowth for Thinning Hair, Topical Hair Loss Treatment, Unscented Topical Aerosol, Results in 8–16 Weeks, 3-Month Supply, 3 x 2.11 oz', 'mens-rogaine-5-minoxidil-for-men-foam-clinically-proven-regrowth-for-thinning-hair-topical-hair-loss-treatment-unscented-topical-aerosol-results-in-816-weeks-3-month-supply-3-x-211-oz', 'NH_123', 'Medicine and Supplements', 'Amazon USA', 7474.00, 6418.00, 9, 0.00, 0, 1, 'published', NULL, 'products/images/MsUAZmfGIHVAR56OisTPSk2UDa8duVq1oYLFsX9k.png', '<p>Men’s Rogaine 5% Minoxidil for Men Foam, Clinically Proven Regrowth for Thinning Hair, Topical Hair Loss Treatment, Unscented Topical Aerosol, Results in 8–16 Weeks, 3-Month Supply, 3 x 2.11 oz</p>', 'Men’s Rogaine 5% Minoxidil for Men Foam, Clinically Proven Regrowth for Thinning Hair, Topical Hair Loss Treatment, Unscented Topical Aerosol, Results in 8–16 Weeks, 3-Month Supply, 3 x 2.11 oz', 'Men’s Rogaine 5% Minoxidil for Men Foam, Clinically Proven Regrowth for Thinning Hair, Topical Hair Loss Treatment, Unscented Topical Aerosol, Results in 8–16 Weeks, 3-Month Supply, 3 x 2.11 oz | Amazon USA', 'Shop Men’s Rogaine 5% Minoxidil for Men Foam, Clinically Proven Regrowth for Thinning Hair, Topical Hair Loss Treatment, Unscented Topical Aerosol, Results in 8–16 Weeks, 3-Month Supply, 3 x 2.11 oz. High quality product with great features.', '2026-03-30 23:59:11', '2026-04-04 12:29:57'),
(11, 'Optimum Nutrition Micronized Creatine Monohydrate Powder, Unflavored, 120 Servings, 600 Grams (Packaging May Vary)', 'optimum-nutrition-micronized-creatine-monohydrate-powder-unflavored-120-servings-600-grams-packaging-may-vary', 'SKU_123', 'Medicine and Supplements', 'Amazon USA', 5089.00, 4371.00, 10, 0.00, 0, 0, 'published', NULL, 'products/images/Ai949ZzyjAVMA9dDjpoxua8J0BrNkiaUQUJ8abi9.png', '<p>Optimum Nutrition Micronized Creatine Monohydrate Powder, Unflavored, 120 Servings, 600 Grams (Packaging May Vary)</p><p><br></p>', 'Optimum Nutrition Micronized Creatine Monohydrate Powder, Unflavored, 120 Servings, 600 Grams (Packaging May Vary)', 'Optimum Nutrition Micronized Creatine Monohydrate Powder, Unflavored, 120 Servings, 600 Grams (Packaging May Vary) | Amazon USA', 'Shop Optimum Nutrition Micronized Creatine Monohydrate Powder, Unflavored, 120 Servings, 600 Grams (Packaging May Vary). High quality product with great features.', '2026-03-31 00:03:44', '2026-04-03 23:34:32'),
(12, 'Sports Research® Omega-3 Fish Oil 1250 - Triple Strength Fish Oil Supplement from Wild Alaska Pollock - MSC Certified Sustainable · Non-GMO · Soy Free - 90 Softgel Capsules', 'sports-research-omega-3-fish-oil-1250-triple-strength-fish-oil-supplement-from-wild-alaska-pollock-msc-certified-sustainable-non-gmo-soy-free-90-softgel-capsules', 'GH-123', 'Medicine and Supplements', 'Amazon USA', 4189.00, 3414.00, 8, 0.00, 0, 1, 'published', NULL, 'products/images/hZQIn5Z8gABGDTvI0xiBJeF7kdXDU2V6yYCEQKP3.png', NULL, 'Sports Research® Omega-3 Fish Oil 1250 - Triple Strength Fish Oil Supplement from Wild Alaska Pollock - MSC Certified Sustainable · Non-GMO · Soy Free - 90 Softgel Capsules', 'Sports Research® Omega-3 Fish Oil 1250 - Triple Strength Fish Oil Supplement from Wild Alaska Pollock - MSC Certified Sustainable · Non-GMO · Soy Free - 90 Softgel Capsules | Amazon USA', 'Shop Sports Research® Omega-3 Fish Oil 1250 - Triple Strength Fish Oil Supplement from Wild Alaska Pollock - MSC Certified Sustainable · Non-GMO · Soy Free - 90 Softgel Capsules. High quality product with great features.', '2026-03-31 00:07:14', '2026-04-03 23:13:17'),
(13, 'SIMPLE Kind to Skin Soothing Toner 200ml', 'simple-kind-to-skin-soothing-toner-200ml', 'Watson-123', 'Beauty & Health', 'Watson', 1229.00, 1002.00, 20, 0.00, 0, 0, 'published', NULL, 'products/images/QxFwtMWXE8FWCwi421THSJo1b3C29zORyn7V2YhJ.png', '<p>Product Features &amp; Benefits:</p><p>1) Chamomile soothes &amp; softens dry, rough &amp; sore skin.</p><p>2) Witch Hazel tones and tightens pores while Allantoin softens and protects skin.</p><p>3) Pro-Vitamin B5 restores, softens and smoothes skin.</p><h4 style=\"font-family: Cinzel, Bangla493, serif;\">Product Usage</h4><p>Step 1: Apply generously to cotton wool.</p><p>Step 2: Wipe in gentle upward movements over skin morning and night.</p><h4 style=\"font-family: Cinzel, Bangla493, serif;\">Ingredients</h4><p>Aqua, Hydrogenated Starch Hydrolysate, Hamamelis Virginiana Water, Allantoin, Panthenol, Niacinamide, Chamomilla Recutita Flower Extract, Sodium PCA, Glycerin, Pantolactone, Disodium Laureth Sulfosuccinate, Citric acid, Methylparaben, 2-Bromo-2-Nitropropane-1,3-Diol, Potassium sorbate.</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla493, serif;\">Skin Type</h4><p>FOR ALL</p>', 'Description\r\nSoothing Facial Toner 200ml\r\nProduct Description: 100% alcohol free toner removes any alkaline residue left after cleansing, leaves skin soft with no dryness', 'SIMPLE Kind to Skin Soothing Toner 200ml | Watson', 'Shop Simple Kind to Skin Soothing Toner 200ml. High quality product with great features.', '2026-04-04 17:23:21', '2026-04-04 17:49:06'),
(14, 'Vitalitown Vitamin D3 K2 Supplement, Vitamin D3 10000 IU Vitamin K2 (MK7) 200 mcg, 90 Softgels, Non-GMO, No Gluten & Soy, for Bone, Teeth, Immune & Heart Health', 'vitalitown-vitamin-d3-k2-supplement-vitamin-d3-10000-iu-vitamin-k2-mk7-200-mcg-90-softgels-non-gmo-no-gluten-soy-for-bone-teeth-immune-heart-health', 'Vitalitown Vitamin D3 K2-10', 'Medicine and Supplements', 'Amazon USA', 2515.00, 1758.99, 1, 0.00, 0, 1, 'published', NULL, 'products/images/pUPBc6kr701U5LPW77szC0YG7uFHxlYw6eM1dT5M.png', '<h2 style=\"font-family: Cinzel, Bangla254, serif;\"><strong>About this item</strong></h2><ul><li>Vitamin D3 10000 IU &amp; Vitamin K2 200 mcg Per Tiny Softgel: Vitalitown extra strength Vitamin D3 + K2 provides a whopping 10000 IU of vitamin D and 200 mcg of vitamin K2 per easy to swallow softgel, designed for those with limited sunlight exposure or higher vitamin D needs.* No worry anymore about sunless days!</li><li>Highly Bioavailable Vitamin D3 &amp; K2: Our vitamin D3 is the same form of vitamin D naturally produced by your body when exposed to sunlight, giving you the same health benefits of sunshine without UV damage.* And the vitamin K2 is in its top-grade menaquinone-7 (MK-7) form for higher bioavailability &amp; longer retention. We\'ve gone a step further by infusing cold-pressed sunflower oil to maximize the absorption of these two fat-soluble vitamins.</li></ul><p><br></p>', 'Vitalitown Vitamin D3 K2 Supplement, Vitamin D3 10000 IU Vitamin K2 (MK7) 200 mcg, 90 Softgels, Non-GMO, No Gluten & Soy, for Bone, Teeth, Immune & Heart Health', 'Vitalitown Vitamin D3 K2 Supplement, Vitamin D3 10000 IU Vitamin K2 (MK7) 200 mcg, 90 Softgels, Non-GMO, No Gluten & Soy, for Bone, Teeth, Immune & Heart Health | Amazon USA', 'Shop Vitalitown Vitamin D3 K2 Supplement, Vitamin D3 10000 IU Vitamin K2 (MK7) 200 mcg, 90 Softgels, Non-GMO, No Gluten & Soy, for Bone, Teeth, Immune & Heart Health. High quality product with great features.', '2026-04-09 16:25:48', '2026-04-11 10:52:06'),
(15, 'Kirkland Signature Minoxidil Topical Solution USP 5%, Extra Strength Hair Regrowth Treatment for Men, 6 Months Supply', 'kirkland-signature-minoxidil-topical-solution-usp-5-extra-strength-hair-regrowth-treatment-for-men-6-months-supply', 'Kirkland Signature Minoxidil', 'Medicine and Supplements', 'Amazon USA', 8709.00, 5415.00, 5, 0.00, 0, 1, 'published', NULL, 'products/images/MQfGr8sPZLgUYMPA3BXb1AxqCHay2gwmmeFZZIZj.png', '<h3><strong>Product Specifications</strong></h3><ul><li><strong style=\"color: rgb(255, 255, 255);\">Concentration:</strong><span style=\"color: rgb(255, 255, 255);\"> 5% Minoxidil Topical Solution USP.</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Quantity:</strong><span style=\"color: rgb(255, 255, 255);\"> 6 bottles (60 mL each).</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Supply:</strong><span style=\"color: rgb(255, 255, 255);\"> 180-day (6-month) supply.</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Format:</strong><span style=\"color: rgb(255, 255, 255);\"> Liquid solution with an included child-resistant dropper</span>.</li></ul><h3><strong>Detailed Product Benefits</strong></h3><ul><li><strong style=\"color: rgb(255, 255, 255);\">Proven Regrowth:</strong><span style=\"color: rgb(255, 255, 255);\"> Minoxidil is the #1 dermatologist-recommended over-the-counter active ingredient for hair regrowth.</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Follicle Activation:</strong><span style=\"color: rgb(255, 255, 255);\"> It works by increasing blood flow to the hair follicles, which can help shift hair from a resting phase into an active growth phase.</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Cost-Effective:</strong><span style=\"color: rgb(255, 255, 255);\"> As a Kirkland Signature (Costco) brand, it offers the same active ingredient as national brands like Rogaine® but at a significantly lower price point per month.</span></li></ul><h3><strong>What to Expect During Use</strong></h3><ol><li><strong style=\"color: rgb(255, 255, 255);\">The \"Shedding\" Phase:</strong><span style=\"color: rgb(255, 255, 255);\"> During the first 2–6 weeks, some users may notice a temporary increase in hair shedding. This is often a sign that the old hairs are making way for new, healthier strands.</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Early Growth:</strong><span style=\"color: rgb(255, 255, 255);\"> Initial regrowth is often soft, colorless, and \"peach fuzz\" like.</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Mature Growth:</strong><span style=\"color: rgb(255, 255, 255);\"> With continued use, the new hair typically becomes the same color and thickness as your</span> existing hair.</li></ol><h3><strong>Application Guidelines</strong></h3><ul><li><strong style=\"color: rgb(255, 255, 255);\">Clean Scalp:</strong><span style=\"color: rgb(255, 255, 255);\"> Ensure your scalp and hair are completely dry before application.</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Direct Contact:</strong><span style=\"color: rgb(255, 255, 255);\"> Use the dropper to apply the solution directly to the skin of the scalp, not the hair strands.</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Frequency:</strong><span style=\"color: rgb(255, 255, 255);\"> Apply twice daily (once in the morning and once at night). Using more than the recommended dose will not speed up results and may increase the risk of side effects.</span></li></ul><h3><strong>Safety Warnings</strong></h3><ul><li><strong style=\"color: rgb(255, 255, 255);\">For Men Only:</strong><span style=\"color: rgb(255, 255, 255);\"> This product is not for use by women due to the high concentration of Minoxidil.</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Scalp Health:</strong><span style=\"color: rgb(255, 255, 255);\"> Do not use if your scalp is red, inflamed, infected, irritated, or painful.</span></li><li><strong style=\"color: rgb(255, 255, 255);\">Medical Conditions:</strong><span style=\"color: rgb(255, 255, 255);\"> C</span>onsult a doctor before use if you have any underlying heart conditions.</li></ul><p><br></p>', 'Kirkland Signature Minoxidil Topical Solution USP 5%, Extra Strength Hair Regrowth Treatment for Men, 6 Months Supply', 'Kirkland Signature Minoxidil Topical Solution USP 5%, Extra Strength Hair Regrowth Treatment for Men, 6 Months Supply | Amazon USA', 'Shop Kirkland Signature Minoxidil Topical Solution USP 5%, Extra Strength Hair Regrowth Treatment for Men, 6 Months Supply. High quality product with great features.', '2026-04-11 12:21:32', '2026-04-11 12:22:39'),
(16, 'NOW Foods Supplements, Magnesium Glycinate 100 mg, Highly Absorbable Form, 180 Tablets', 'now-foods-supplements-magnesium-glycinate-100-mg-highly-absorbable-form-180-tablets', 'NOW Foods Supplements', 'Medicine and Supplements', 'Amazon USA', 3918.00, 3418.00, 20, 0.00, 0, 1, 'published', '[{\"name\":\"Size\",\"values\":[{\"name\":\"S\",\"price_adjustment\":0},{\"name\":\"M\",\"price_adjustment\":0},{\"name\":\"L\",\"price_adjustment\":0}]}]', 'products/images/TcR0fGyr0JtwW8ss4YrxBBWTCHlTuBAt8KuG1EgW.png', '<h2><strong>About this item</strong></h2><ul><li>HIGHLY ABSORBABLE FORM: Magnesium glycinate utilizes magnesium bound to the amino acid glycine, which facilitates intestinal absorption*</li><li>SUPPORTS HEALTHY MUSCLE, NERVE, AND HEART FUNCTIONS*: Magnesium is a mineral that is critical for energy production and metabolism, muscle contraction, nerve impulse transmission, and bone mineralization*</li><li>SUGGESTED USAGE: Take 2 tablets 1 to 2 times daily with food</li><li>GMP Quality Assured: A-rated, third-party certification means that every aspect of the NOW manufacturing process has been examined. Our in-house laboratories are ISO/IEC accredited for laboratory testing including for stability, potency and product formulation.</li><li>Founded in 1968 by Elwood Richard, NOW is one of the largest independent, family- and employee-owned manufacturers of natural products</li></ul><p><br></p>', 'NOW Foods Supplements, Magnesium Glycinate 100 mg, Highly Absorbable Form, 180 Tablets', 'NOW Foods Supplements, Magnesium Glycinate 100 mg, Highly Absorbable Form, 180 Tablets | Amazon USA', 'Shop NOW Foods Supplements, Magnesium Glycinate 100 mg, Highly Absorbable Form, 180 Tablets. High quality product with great features.', '2026-04-11 13:45:20', '2026-04-11 14:00:09'),
