(56, 'WATSONS Cherry Blossom Scented Cream Body Wash 1L', 'watsons-cherry-blossom-scented-cream-body-wash-1l', 'Watson=23', 'Today\'s Deals', 'Watson', 1955.99, 1599.00, 4, 0.00, 0, 0, 'published', NULL, 'products/images/GEaOipOzjO3z6S6NkD7tIbvMPGy6BxH3iorwuyFP.png', '<p>Product Details</p><p>Hide</p><p>Description</p><p>Promote a reduced usage of virgin materials by using recycled content insteadThe bottle is made with 50% recycled plastic.Watsons Cherry Blossom Scented Cream Body Wash cleanses your body and retains skin moisture with a delicate &amp; delightful scent</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla871, serif;\">Product Usage</h4><p>Pump directly onto the palm or a sponge. Work into a lather and apply to your body, then rinse off with water</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla871, serif;\">Ingredients</h4><p>Aqua, Sodium Laureth Sulfate, Palm Kernelamide DEA, Sodium Chloride, Cocamidopropyl Betaine, Parfum, Styrene/Acrylates Copolymer, DMDM Hydantoin, Citric Acid, Glycerin, Tetrasodium EDTA, Sodium Benzoate, Tocopheryl Acetate, Hexyl Cinnamal, Linalool, CI 16035</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla871, serif;\">Warnings</h4><p>Keep out of reach of children. Avoid direct contact with eyes. If contact occurs, rinse immediately with water. If any irritation occurs, stop use and consult a doctor if necessary.</p>', 'WATSONS\r\nCherry Blossom Scented Cream Body Wash 1L', 'WATSONS Cherry Blossom Scented Cream Body Wash 1L | Watson', 'Shop WATSONS Cherry Blossom Scented Cream Body Wash 1L. High quality product with great features.', '2026-04-17 23:59:36', '2026-04-17 23:59:50'),
(57, 'Hyaluronan Hydrating Black Mask 5\'s', 'hyaluronan-hydrating-black-mask-5s', 'Watson=35', 'Beauty & Personal Care', 'Watson', 2500.00, 2136.00, 10, 0.00, 0, 1, 'published', NULL, 'products/images/DDbxPdazGNnrfHq70w2dbi1IZaXM8obOPhGEBR79.png', '<p>Product Details </p><p>Description</p><p>Hyaluronan provides moisturizing power to skin and can effectively improve rough, dry, and cracked skin conditions. Pure hyaluronan provides refreshing sensation when using and can be easily absorbed by your skin and can thus provide your skin with the additional moisture it needs with a silky, smooth touch.Product Features &amp; Benefits:After microemulsification technology, small molecules penetrate into the skin and completely absorb the essence</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla969, serif;\">Product Usage</h4><p>After facial cleansing, open the mask and apply flat on the mask. Use fingers to gently adjust the mask until it is properly attached to the face. Wait for 15 to 20 minutes before removing the mask. Pat the essence on the face gently until it is fully absorbed by the skin. Cleanse face once again by individual preference even though not necessary.</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla969, serif;\">Ingredients</h4><p>Water, Propylene, Glycol, Glycerin、Phenoxyethanol, Chlorphenesin、Cucumis Sativus (Cucumber) Fruit Extract、Jojoba Wax Peg-120 Esters, Sodium Hyaluronate, Acrylates/C10-30 Alkyl Acrylate Crosspolymer, Dipotassium Glycyrrhizate, Xanthan Gum, Hydroxyethyl Urea、Imperata Cylindrica Root Extract、Tocopheryl Acetate, Nasturtium Officinale Flower/Leaf Extract, Tranexamic Acid、Fragrance, Iodopropynyl Butylcarbamate, Sclerotium Gum, Arbutin, PEG-60 Hydrogenated Castor Oil, Polyglutamic Acid。</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla969, serif;\">Skin Type</h4><p>FOR ALL</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla969, serif;\">Warnings</h4><p>Avoid direct contact with eyes. If contact occurs, rinse eyes thoroughly with water immediately.</p><p>If skin allergic reactions occur, stop using product immediately.</p><p>Product inedible. For external use only.Not to be used for children under three years of age.</p><h4 style=\"font-family: Cinzel, Bangla969, serif;\">Width (cm)</h4><p>11</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla969, serif;\">Height (cm)</h4><p>16</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla969, serif;\">Depth (cm)</h4><p>3</p>', 'Hyaluronan Hydrating Black Mask 5\'s', 'Hyaluronan Hydrating Black Mask 5\'s | Watson', 'Shop Hyaluronan Hydrating Black Mask 5\'s. High quality product with great features.', '2026-04-18 11:18:25', '2026-04-18 12:40:26'),
(58, 'NATURE\'S BOUNTY Calcium Magnesium +D 2 x 60\'s', 'natures-bounty-calcium-magnesium-d-2-x-60s', 'NATURE\'S BOUNTY', 'Health Care', 'Watson', 3800.00, 3356.00, 4, 0.00, 0, 1, 'published', NULL, 'products/images/UXDh83qRfaxby14re7LB5sPpYRrzd8p1qBD9MVid.png', '<p>Product Details</p><p>Hide</p><p>Description</p><p>Calcium Magnesium +D 2 x 60\'s (*MAL Item)</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla234, serif;\">Origin</h4><p>USA</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla234, serif;\">Product Usage</h4><p>For adults, take two (2) caplets daily, preferably with a meal. As a reminder, discuss the supplements and medications you take with your doctor or pharmacist.</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla234, serif;\">Ingredients</h4><p>NB CALCIUM MAGNESIUM D 2X60S</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla234, serif;\">Width (cm)</h4><p>12</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla234, serif;\">Height (cm)</h4><p>11.7</p><p><br></p><h4 style=\"font-family: Cinzel, Bangla234, serif;\">Depth (cm)</h4><p>6</p>', 'NATURE\'S BOUNTY Calcium Magnesium +D 2 x 60\'s', 'NATURE\'S BOUNTY Calcium Magnesium +D 2 x 60\'s | Watson', 'Shop NATURE\'S BOUNTY Calcium Magnesium +D 2 x 60\'s. High quality product with great features.', '2026-04-18 11:34:39', '2026-04-27 23:15:52'),
(59, 'Viviscal Hair Growth Supplements for Women', 'viviscal-hair-growth-supplements-for-women', 'Viviscal Hair Growth', 'Health Care', 'Amazon USA', 15217.00, 13786.00, 5, 0.00, 0, 1, 'published', NULL, 'products/images/3vlBnod2nSACCalxHcDZITurAujCnwFVBRl7i9QT.png', '<p><br></p><h2 style=\"font-family: Cinzel, Bangla730, serif;\"><strong>Product Description</strong></h2><p>Viviscal Hair Growth Supplements for Women deliver a clinically proven solution to help women achieve thicker hair, fuller hair, and healthier growth. Backed by over 25 years of research and trusted by millions worldwide, Viviscal supports existing hair growth and reduces hair shedding in as little as 3 months. Formulated with a unique blend of Marine Collagen, Biotin, Zinc, Vitamin C, and Iron, this drug-free hair growth supplement nourishes thinning hair from within, helping to strengthen strands and promote natural hair regrowth. These hair vitamins are designed for women experiencing hair thinning or hair loss due to stress, postpartum changes, hormonal shifts, or aging. Viviscal is suitable for all hair types — including color-treated, fine, or thinning hair — and works alongside your daily hair care routine. Clinical studies show significant improvements in hair volume and reduced shedding, making it a trusted choice for women’s hair growth. Each bottle contains a 3-month supply (180 tablets) for consistent use and long-term support. Take two tablets daily to help restore confidence, improve hair health, and enjoy visibly thicker, fuller hair.</p>', 'Viviscal Hair Growth Supplements for Women, Thicker Fuller Hair Support for Thinning Hair and Hair Loss, with Biotin and Marine Collagen, Drug-Free, 180 Tablets, 90-Day Supply', 'Viviscal Hair Growth Supplements for Women | Amazon USA', 'Shop Viviscal Hair Growth Supplements for Women. High quality product with great features.', '2026-04-18 12:24:31', '2026-04-27 23:15:26'),
(60, 'Nordic Naturals Ultimate Omega, Lemon Flavor - 90 Soft Gels - 1280 mg Omega-3', 'nordic-naturals-ultimate-omega-lemon-flavor-90-soft-gels-1280-mg-omega-3', 'Nordic Naturals Ultimate Omega', 'Health Care', 'Amazon USA', 6566.00, 5631.00, 7, 0.00, 0, 1, 'published', NULL, 'products/images/DyVYuFgcJjHNJnysmfgFLm71fA9LfAmSKNFCCRL1.png', '<p><br></p><p><span style=\"background-color: rgb(0, 0, 0); color: rgb(255, 255, 255);\">&nbsp;While we work to ensure that product information is correct, on occasion manufacturers may alter their ingredient lists. Actual product packaging and materials may contain more and/or different information than that shown on our Web site. We recommend that you do not solely rely on the information presented and that you always read labels, warnings, and directions before using or consuming a product. For additional information about a product, please contact the manufacturer. Content on this site is for reference purposes and is not intended to substitute for advice given by a physician, pharmacist, or other licensed health-care professional. You should not use this information as self-diagnosis or for treating a health problem or disease. Contact your health-care provider immediately if you suspect that you have a medical problem. Information and statements regarding dietary supplements have not been evaluated by the Food and Drug Administration and are not intended to diagnose, treat, cure, or prevent any disease or health condition. Amazon.com assumes no liability for inaccuracies or misstatements about products.</span></p>', 'Nordic Naturals Ultimate Omega, Lemon Flavor - 90 Soft Gels - 1280 mg Omega-3 - High-Potency Omega-3 Fish Oil Supplement with EPA & DHA - Promotes Brain & Heart Health - Non-GMO - 45 Servings', 'Nordic Naturals Ultimate Omega, Lemon Flavor - 90 Soft Gels - 1280 mg Omega-3 | Amazon USA', 'Shop Nordic Naturals Ultimate Omega, Lemon Flavor - 90 Soft Gels - 1280 mg Omega-3. High quality product with great features.', '2026-04-18 12:36:03', '2026-04-27 23:15:06'),
(61, 'Horbäach Cranberry Concentrate Extract Pills + Vitamin C', 'horbach-cranberry-concentrate-extract-pills-vitamin-c', 'Horbäach Cranberry Concentrate', 'Health Care', 'Amazon USA', 2830.00, 2330.00, 5, 0.00, 0, 1, 'published', NULL, 'products/images/wXSefjrCuTyhHuiph1CL3jaXMFO0CsN9eucBNDqZ.png', '<h2 style=\"font-family: Cinzel, Bangla865, serif;\"><strong>About this item</strong></h2><ul><li>CRANBERRY FRUIT: A great source of Vitamins C &amp; E, and naturally occurring Polyphenols</li><li>HERBAL SUPPLEMENT: Provides potent Cranberry plus Vitamin C in each serving</li><li>EXPERTLY CRAFTED: Our professional formula is backed by our commitment to purity and potency</li><li>HORBAACH MANUFACTURERS: Laboratory Tested, Trusted Ingredients, Superior Quality, 100% Guaranteed!</li><li>NATURALLY FREE OF: Gluten, Wheat, Yeast, Lactose, Artificial Flavor, Artificial Color &amp; Non-GMO</li></ul><p><br></p>', 'Horbäach Cranberry Concentrate Extract Pills + Vitamin C | 120 Capsules | Supplement for Women and Men | Triple Strength Ultimate Potency Formula | Non-GMO and Gluten Free', 'Horbäach Cranberry Concentrate Extract Pills + Vitamin C | Amazon USA', 'Shop  Horbäach Cranberry Concentrate Extract Pills + Vitamin C . High quality product with great features.', '2026-04-18 13:05:57', '2026-04-27 23:14:39'),
(62, 'Anker Smart Display Charger,Anker Nano 45W Max GaN Fast Charging USB', 'anker-smart-display-chargeranker-nano-45w-max-gan-fast-charging-usb-c-charger-block', 'Anker Smart Display Charger,Anker Nano 45W', 'Gadget & Gear', 'Amazon USA', 6557.99, 4719.00, 7, 0.00, 0, 1, 'published', NULL, 'products/images/9ee664RwVMHNrJ7Z68OEdHrVX3H5WImzq59gP7fR.png', '<h1 style=\"font-family: Cinzel, Bangla865, serif;\"><strong>About this item</strong></h1><ul><li>Smart iPhone Recognition with Care Mode: Automatically recognizes supported iPhone models and adjusts charging for smarter, safer power delivery. Compatible only with iPhone 17 / 16 / 15 series, 11\" iPad Pro (2024 / 2023 / 2021 / 2020), 12.9\" iPad Pro (2022 / 2021 / 2020), and 13\" iPad Pro (2024).Excluding iPhone 17e.</li><li>45W Max Fast Charging with Smart Power Adjustment: Delivers up to 45W of high-speed charging while adjusting output based on your battery level. Charge iPhone 17 Pro to 50% in just 20 minutes. (Note: Data based on internal lab testing. Actual performance may vary depending on usage conditions.)</li><li>Smart Display Controls: Tap once to view real-time charging status, double-tap to switch between modes, and press for 2 seconds to rotate the screen. The display automatically turns off after 1 minute. For more details, scan the QR code to view the user manual.</li><li>Extends Battery Life: TÜV-certified Care Mode lowers charging temperature by up to 9°F compared to standard 45W chargers—ideal for overnight charging.</li><li>Pocket-Sized with Dual Foldable Prongs: Approximately 47% smaller and 36% lighter than the original 30W charger. Features both 90° and 180° foldable prongs for easy use in tight spaces.</li><li>What You Get: Anker Nano Charger (45W, Smart Display, 180° Foldable), welcome guide, 18-month coverage, and our friendly customer service.</li><li>Note: The display rotates 180° but does not rotate 90°. This charger does not have a touchscreen. For display navigation, refer to the user manual.</li></ul><p><br></p>', 'Anker Smart Display Charger,Anker Nano 45W Max GaN Fast Charging USB C Charger Block,180° Foldable Plug,Smart Recognition,Built-in Care Mode,for...', 'Anker Smart Display Charger,Anker Nano 45W Max GaN Fast Charging USB C Charger Block', 'Shop Anker Smart Display Charger,Anker Nano 45W Max GaN Fast Charging USB C Charger Block. High quality product with great features.', '2026-04-18 13:21:32', '2026-04-18 13:22:30'),
(63, 'Anker Laptop Power Bank, 25,000mAh Portable Charger', 'anker-laptop-power-bank-25000mah-portable-charger', 'Anker Laptop Power Bank', 'Gadget & Gear', 'Amazon USA', 21975.00, 16000.00, 12, 0.00, 0, 1, 'published', NULL, 'products/images/4WvuP4QnbUMgyZmumzuWCUbxIqpaWBLQHhftbkGm.png', '<h1 style=\"font-family: Cinzel, Bangla865, serif;\"><strong>About this item</strong></h1><ul><li>Triple 100W USB-C Ports for Multi-Device Charging: Ideal for laptop users, this 25,000mAh power bank features three 100W USB-C ports for simultaneous charging—perfect for remote work, home offices, or powering up multiple devices on the go.</li><li>25,000mAh for Long-Haul Power: Tackle week-long trips or extended camping with 25,000mAh capacity and ultra-fast recharging, reaching 30% in just 22 minutes. (Note: Complies with 100Wh airline restrictions and is airline carry-on friendly.)</li><li>Dual Built-In Cables for Travel: Features two USB-C cables, one extendable up to 2.3 ft with 20,000 retractions, and another at 0.98 ft cable that doubles as a durable carrying strap capable of enduring more than 20,000 bends. Built to handle family travel, outdoor activities, and emergency backup needs.</li><li>Charge 4 Devices at Once: Power up smartphones, tablets, or other USB-enabled devices thanks to dual USB-C cables, a USB-A port, and a USB-C port.</li><li>What You Get: Anker Power Bank (25K, 165W, Built-In and Retractable Cables), protective pouch, user manual, 18-month warranty, and our friendly customer service. (Note: Charger shown in the video is not included.)</li></ul><p><br></p>', 'Anker Laptop Power Bank, 25,000mAh Portable Charger with Triple 100W USB-C Ports, Built-in Retractable Cables, Flight-Approved for Travel, iPhone 17/16 Series, MacBook, Samsung, and More', 'Anker Laptop Power Bank, 25,000mAh Portable Charger | Amazon USA', 'Shop  Anker Laptop Power Bank, 25,000mAh Portable Charger. High quality product with great features.', '2026-04-18 14:10:59', '2026-04-18 14:11:45'),
(64, 'Aveeno Skin Relief Moisturising Body Wash', 'aveeno-skin-relief-moisturising-body-wash', 'Aveeno Skin Relief Moisturising Body Wash', 'Beauty & Personal Care', 'Amazon UK', 3278.00, 2598.00, 5, 0.00, 0, 0, 'published', NULL, 'products/images/NlsatmE6ruKjez0W485CduOY9eQ8KrPEhlcLRTKJ.png', '<h1 style=\"font-family: Cinzel, Bangla865, serif;\"><strong>About this item</strong></h1><ul><li>Cleansed and moisturised: This innovative body cleanser is designed to clean the skin gently, removing impurities and dirt without drying out the skin, leaving it soothed and nourished</li><li>Soothing and nourishing: Formula with soothing Triple Oat Complex. When used as a regimen, AVEENO Skin Relief Body Lotion and Wash help to improve the skin\'s natural microbiome balance, leaving you with more resilient skin</li><li>Dermatologist tested: The body wash for dry skin is suitable for very dry, sensitive skin. Its unique formula is 95% biodegradable, vegan*, hypoallergenic**, unscented, and soap-free</li><li>Application instructions: Massage the Aveeno body cleanser into wet skin and rinse away thoroughly. Complete your routine with Aveeno Skin Relief Moisturising Body Lotion</li><li>Product details: Aveeno Skin Relief Moisturising Body Wash (1x 500ml), soothing body wash with nourishing Triple Oat Complex, gentle cleansing wash for hydrating very dry, sensitive skin</li></ul><p><br></p>', 'Aveeno Skin Relief Moisturising Body Wash (1x 500ml), Gentle Cleansing Wash with Soothing Triple Oat Complex, Soap-Free, Unscented for Sensitive and Very Dry Skin', 'Aveeno Skin Relief Moisturising Body Wash (1x 500ml), Gentle Cleansing Wash with Soothing', 'Shop Aveeno Skin Relief Moisturising Body Wash (1x 500ml), Gentle Cleansing Wash with Soothing. High quality product with great features.', '2026-04-18 15:09:21', '2026-04-18 15:10:00');
